-- ============================================
-- Legislacao full-site: requiao-filho / ALEP Transparencia / projetos_lei
-- Seed ampliado_parcial: autoria principal parlamentar estadual ALEP
-- ============================================
-- Fonte oficial:
--   https://transparencia.assembleia.pr.leg.br/plenario/atividade-por-parlamentar
--   https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/{arquivo}.pdf
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = requiao-filho-alep-autoria-principal-ampliado-parcial-20260507
--   coverage_scope = inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507
--
-- Filtro factual: AUTOR 593 - DEPUTADO REQUIÃO FILHO,
-- AUTORES inicia por DEPUTADO REQUIÃO FILHO, tipos fonte aceitos PRO/PLC/PEC,
-- numero/ano/ementa/protocolo D.A.P. presentes e zero escrita em legislacao_mandato_executivo.

DO $$
DECLARE
  cand_id uuid;
  current_pl_count int;
  current_lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'requiao-filho' AND publicavel = true;

  IF cand_id IS NULL THEN
    RAISE NOTICE 'requiao-filho: pre-condicao pulada porque candidato publico nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO current_pl_count FROM projetos_lei WHERE candidato_id = cand_id;
  SELECT count(*) INTO current_lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;

  IF current_pl_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao requiao-filho: projetos_lei esperado 0, encontrado %', current_pl_count;
  END IF;

  IF current_lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao requiao-filho: legislacao_mandato_executivo esperado 0, encontrado %', current_lme_count;
  END IF;
END $$;

