    ('PL', '287', 2019, 'DETERMINA QUE AS EMPRESAS ESTATAIS E CONCESSIONÁRIAS QUE PRESTAM SERVIÇOS PÚBLICOS DE ABASTECIMENTO DE ÁGUA E FORNECIMENTO DE LUZ VEICULEM NAS CONTAS MENSAIS ENVIADAS AO CONSUMIDOR OS TELEFONES QUE ESPECIFICA.', 'ALEP Transparencia', 'ALEP-AUTORIA:593:PL:287/2019:DAP-1656/2019', 'https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf', 'requiao-filho-alep-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507', '{"source":"ALEP Transparencia","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"requiao-filho-alep-autoria-lote-a-20260507","coverage_id":"requiao-filho-alep-autoria-principal-ampliado-parcial-20260507","coverage_scope":"inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"alep_author_code":593,"alep_source_type_code":"PRO","alep_source_title":"PROJETO DE LEI 287/2019","alep_protocolo_dap":"1656/2019","official_page_url":"https://transparencia.assembleia.pr.leg.br/plenario/atividade-por-parlamentar","official_pdf_url":"https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf","official_pdf_label":"19ª LEGISLATURA (2019 - 2022) - PDF","periodo":"01/02/2019 ATÉ 31/12/2022","autores_raw":"DEPUTADO REQUIÃO FILHO","autoria_principal_verificada":true,"fonte_oficial_verificada_em":"2026-05-07T22:56:11.040Z"}'::jsonb),
