    ('PL', '197', 2019, 'DISPÕE SOBRE A VEDAÇÃO DA NOMEAÇÃO PARA CARGOS PÚBLICOS, NOS TRÊS PODERES DO ESTADO DO PARANÁ, DE PESSOAS QUE TENHAM SIDO CONDENADAS PELA LEI N° 11.340 DE 11 DE AGOSTO DE 2006 - LEI MARIA DA PENHA.', 'ALEP Transparencia', 'ALEP-AUTORIA:593:PL:197/2019:DAP-1086/2019', 'https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf', 'requiao-filho-alep-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507', '{"source":"ALEP Transparencia","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"requiao-filho-alep-autoria-lote-a-20260507","coverage_id":"requiao-filho-alep-autoria-principal-ampliado-parcial-20260507","coverage_scope":"inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"alep_author_code":593,"alep_source_type_code":"PRO","alep_source_title":"PROJETO DE LEI 197/2019","alep_protocolo_dap":"1086/2019","official_page_url":"https://transparencia.assembleia.pr.leg.br/plenario/atividade-por-parlamentar","official_pdf_url":"https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf","official_pdf_label":"19ª LEGISLATURA (2019 - 2022) - PDF","periodo":"01/02/2019 ATÉ 31/12/2022","autores_raw":"DEPUTADO REQUIÃO FILHO","autoria_principal_verificada":true,"fonte_oficial_verificada_em":"2026-05-07T22:56:11.040Z"}'::jsonb),
