    ('PL', '163', 2019, 'ALTERA A LEI N°15.075, DE 04 DE MAIO DE 2006, QUE AUTORIZA A IMPLANTAÇÃO DO PROGRAMA DE ATENDIMENTO PSICOPEDAGÓGICO E SOCIAL EM TODAS AS UNIDADES ESCOLARES QUE INTEGREM A REDE DE ENSINO PÚBLICO E ALTERA A LEI N° 17.355, DE 10 DE OUTUBRO DE 2012, QUE INSTITUI O PROGRAMA DE COMBATE AO BULLYING, DE AÇÃO INTERDISCIPLINAR E DE PARTICIPAÇÃO COMUNITÁRIA, NAS ESCOLAS PÚBLICAS E PRIVADAS.', 'ALEP Transparencia', 'ALEP-AUTORIA:593:PL:163/2019:DAP-828/2019', 'https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf', 'requiao-filho-alep-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507', '{"source":"ALEP Transparencia","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"requiao-filho-alep-autoria-lote-a-20260507","coverage_id":"requiao-filho-alep-autoria-principal-ampliado-parcial-20260507","coverage_scope":"inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"alep_author_code":593,"alep_source_type_code":"PRO","alep_source_title":"PROJETO DE LEI 163/2019","alep_protocolo_dap":"828/2019","official_page_url":"https://transparencia.assembleia.pr.leg.br/plenario/atividade-por-parlamentar","official_pdf_url":"https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf","official_pdf_label":"19ª LEGISLATURA (2019 - 2022) - PDF","periodo":"01/02/2019 ATÉ 31/12/2022","autores_raw":"DEPUTADO REQUIÃO FILHO","autoria_principal_verificada":true,"fonte_oficial_verificada_em":"2026-05-07T22:56:11.040Z"}'::jsonb),
    ('PL', '127', 2019, 'DETERMINA QUE OS MATERIAIS E LIVROS DIDÁTICOS DE AUTORIA DO PODER PÚBLICO SEJAM FORNECIDOS EM BRAILLE E OBRIGA TODOS OS ESTABELECIMENTOS DE ENSINO ESTABELECIDOS NO ESTADO DO PARANÁ A FORNECEREM HISTÓRICO ESCOLAR, CERTIFICADO E DIPLOMA EM BRAILLE PARA ALUNOS COM DEFICIÊNCIA VISUAL.', 'ALEP Transparencia', 'ALEP-AUTORIA:593:PL:127/2019:DAP-711/2019', 'https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf', 'requiao-filho-alep-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507', '{"source":"ALEP Transparencia","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"requiao-filho-alep-autoria-lote-a-20260507","coverage_id":"requiao-filho-alep-autoria-principal-ampliado-parcial-20260507","coverage_scope":"inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"alep_author_code":593,"alep_source_type_code":"PRO","alep_source_title":"PROJETO DE LEI 127/2019","alep_protocolo_dap":"711/2019","official_page_url":"https://transparencia.assembleia.pr.leg.br/plenario/atividade-por-parlamentar","official_pdf_url":"https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf","official_pdf_label":"19ª LEGISLATURA (2019 - 2022) - PDF","periodo":"01/02/2019 ATÉ 31/12/2022","autores_raw":"DEPUTADO REQUIÃO FILHO","autoria_principal_verificada":true,"fonte_oficial_verificada_em":"2026-05-07T22:56:11.040Z"}'::jsonb),
    ('PL', '39', 2019, 'CRIA O SELO "EMPRESA CONSCIENTE, MEIO AMBIENTE EQUILIBRADO", A SER CONFERIDO AOS ESTABELECIMENTOS COMERCIAIS INSTALADOS NO ESTADO DO PARANÁ QUE PRIORIZAREM O USO DE MATERIAIS COMESTÍVEIS, BIODEGRADÁVEIS, REUTILIZÁVEIS OU PERMANENTES, EM DETRIMENTO DE DESCARTÁVEIS E DETERMINA MEDIDAS DE ESTÍMULO ÀS EMPRESAS AMBIENTALMENTE RESPONSÁVEIS.', 'ALEP Transparencia', 'ALEP-AUTORIA:593:PL:39/2019:DAP-208/2019', 'https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf', 'requiao-filho-alep-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507', '{"source":"ALEP Transparencia","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"requiao-filho-alep-autoria-lote-a-20260507","coverage_id":"requiao-filho-alep-autoria-principal-ampliado-parcial-20260507","coverage_scope":"inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"alep_author_code":593,"alep_source_type_code":"PRO","alep_source_title":"PROJETO DE LEI 39/2019","alep_protocolo_dap":"208/2019","official_page_url":"https://transparencia.assembleia.pr.leg.br/plenario/atividade-por-parlamentar","official_pdf_url":"https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf","official_pdf_label":"19ª LEGISLATURA (2019 - 2022) - PDF","periodo":"01/02/2019 ATÉ 31/12/2022","autores_raw":"DEPUTADO REQUIÃO FILHO","autoria_principal_verificada":true,"fonte_oficial_verificada_em":"2026-05-07T22:56:11.040Z"}'::jsonb),
    ('PL', '6', 2019, 'DISPÕE SOBRE A AUTORIZAÇÃO DE POSSE DE ARMA OFICIAL AOS INTEGRANTES, TRANSFERIDOS PARA A RESERVA REMUNERADA OU APOSENTADOS, DA POLÍCIA MILITAR, CORPO DE BOMBEIROS MILITAR, POLÍCIA CIVIL E DA POLÍCIA CIENTÍFICA DO ESTADO DO PARANÁ.', 'ALEP Transparencia', 'ALEP-AUTORIA:593:PL:6/2019:DAP-90/2019', 'https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf', 'requiao-filho-alep-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507', '{"source":"ALEP Transparencia","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"requiao-filho-alep-autoria-lote-a-20260507","coverage_id":"requiao-filho-alep-autoria-principal-ampliado-parcial-20260507","coverage_scope":"inventario_ampliado_parcial_alep_requiao_filho_autoria_principal_2019_2026_20260507","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"alep_author_code":593,"alep_source_type_code":"PRO","alep_source_title":"PROJETO DE LEI 6/2019","alep_protocolo_dap":"90/2019","official_page_url":"https://transparencia.assembleia.pr.leg.br/plenario/atividade-por-parlamentar","official_pdf_url":"https://transparencia.assembleia.pr.leg.br/storage/atividade_legislativa_parlamentar/Autoria_Proposicoes/3n1XYSIusS3GZF0bbNNA6vu2DQUeMYeF.pdf","official_pdf_label":"19ª LEGISLATURA (2019 - 2022) - PDF","periodo":"01/02/2019 ATÉ 31/12/2022","autores_raw":"DEPUTADO REQUIÃO FILHO","autoria_principal_verificada":true,"fonte_oficial_verificada_em":"2026-05-07T22:56:11.040Z"}'::jsonb);

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'requiao-filho' AND c.publicavel = true
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_requiao_filho_alep_autoria_lote_a AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
